        window.downloadPackSticker = function(stickerId, sampleName) {
            const stickerEl = document.getElementById(stickerId); // РҳСүРөРј СҒСӮСҖРҫРіРҫ РҪСғР¶РҪСӢР№ РјР°РәРөСӮ
            if (!stickerEl) {
                alert('РһСҲРёРұРәР°: РјР°РәРөСӮ РҪР°РәР»РөР№РәРё РҪРө РҪР°Р№РҙРөРҪ РҪР° СҒСӮСҖР°РҪРёСҶРө.');
                return;
            }
            
            if (typeof html2canvas === 'undefined') {
                alert('РңРҫРҙСғР»СҢ РіРөРҪРөСҖР°СҶРёРё РёР·РҫРұСҖР°Р¶РөРҪРёР№ РөСүРө Р·Р°РіСҖСғР¶Р°РөСӮСҒСҸ, РҝРҫРҝСҖРҫРұСғР№СӮРө СҮРөСҖРөР· РҝР°СҖСғ СҒРөРәСғРҪРҙ.');
                return;
            }

            const originalBorder = stickerEl.style.border;
            stickerEl.style.border = 'none';

            html2canvas(stickerEl, {
                scale: 4, 
                backgroundColor: '#ffffff'
            }).then(canvas => {
                stickerEl.style.border = originalBorder;
                
                const link = document.createElement('a');
                link.download = `Sticker_${sampleName}.png`;
                link.href = canvas.toDataURL('image/png');
                link.click();
            });
        };
